const rawContent = $input.item.json.message.content;

// Extract article title (first # heading or first line)
const titleMatch = rawContent.match(/^#\s+(.+)$/m) || rawContent.match(/\*\*Title:\*\*\s*(.+)/m);
const articleTitle = titleMatch ? titleMatch[1].trim() : $('PostgreSQL - Mark Processing').item.json.topic;

// Extract tags if provided
const tagsMatch = rawContent.match(/Tags?:.*?([\w\s,#-]+)(?:\n|$)/i);
const tags = tagsMatch ? tagsMatch[1].split(',').map(t => t.trim().replace('#', '')) : ['devops', 'kubernetes', 'automation'];

// Calculate word count
const wordCount = rawContent.split(/\s+/).length;

// Format timestamp
const now = new Date();
const dateStr = now.toISOString().split('T')[0];

return [{
  json: {
    topic_id: $('PostgreSQL - Mark Processing').item.json.id,
    topic: $('PostgreSQL - Mark Processing').item.json.topic,
    article_title: articleTitle,
    article_content: rawContent,
    word_count: wordCount,
    tags: tags,
    generated_at: now.toISOString(),
    date_str: dateStr
  }
}];
